CREATE OR REPLACE FUNCTION quote.get_devis(p_id integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_rows text[];
  v_body text;
  v_ht numeric(12,2);
  v_tva numeric(12,2);
  v_ttc numeric(12,2);
  d record;
  r record;
BEGIN
  -- List mode (no p_id)
  IF p_id IS NULL THEN
    v_rows := ARRAY[]::text[];
    FOR r IN
      SELECT dv.id, dv.numero, dv.client_id, c.name AS client, dv.objet, dv.statut,
             quote._total_ttc(dv.id, NULL) AS ttc, dv.created_at
        FROM quote.devis dv
        JOIN crm.client c ON c.id = dv.client_id
       ORDER BY dv.created_at DESC
    LOOP
      v_rows := v_rows || ARRAY[
        format('<a href="%s">%s</a>', pgv.call_ref('get_devis', jsonb_build_object('p_id', r.id)), pgv.esc(r.numero)),
        format('<a href="/crm/client?p_id=%s">%s</a>', r.client_id, pgv.esc(r.client)),
        pgv.esc(r.objet),
        quote._statut_badge(r.statut),
        to_char(r.ttc, 'FM999 990.00') || ' EUR',
        to_char(r.created_at, 'DD/MM/YYYY')
      ];
    END LOOP;

    IF array_length(v_rows, 1) IS NULL THEN
      v_body := pgv.empty('Aucun devis', 'Créez votre premier devis pour commencer.');
    ELSE
      v_body := pgv.md_table(ARRAY['Numéro', 'Client', 'Objet', 'Statut', 'Total TTC', 'Date'], v_rows);
    END IF;

    v_body := v_body || format('<p><a href="%s" role="button">Nouveau devis</a></p>', pgv.call_ref('get_devis_form'));
    RETURN pgv.breadcrumb(VARIADIC ARRAY['Devis']) || v_body;
  END IF;

  -- Detail mode
  SELECT dv.*, c.name AS client_name
    INTO d
    FROM quote.devis dv
    JOIN crm.client c ON c.id = dv.client_id
   WHERE dv.id = p_id;

  IF NOT FOUND THEN
    RETURN pgv.empty('Devis introuvable');
  END IF;

  v_ht := quote._total_ht(p_id, NULL);
  v_tva := quote._total_tva(p_id, NULL);
  v_ttc := v_ht + v_tva;

  v_body := pgv.breadcrumb(VARIADIC ARRAY[
    'Devis', pgv.call_ref('get_devis'),
    d.numero
  ]);

  v_body := v_body || pgv.dl(VARIADIC ARRAY[
    'Numéro', d.numero,
    'Client', format('<a href="/crm/client?p_id=%s">%s</a>', d.client_id, pgv.esc(d.client_name)),
    'Objet', pgv.esc(d.objet),
    'Statut', quote._statut_badge(d.statut),
    'Validité', d.validite_jours || ' jours',
    'Date', to_char(d.created_at, 'DD/MM/YYYY'),
    'Total HT', to_char(v_ht, 'FM999 990.00') || ' EUR',
    'Total TVA', to_char(v_tva, 'FM999 990.00') || ' EUR',
    'Total TTC', to_char(v_ttc, 'FM999 990.00') || ' EUR'
  ]);

  -- Lignes
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT l.id, l.description, l.quantite, l.unite, l.prix_unitaire, l.tva_rate,
           round(l.quantite * l.prix_unitaire, 2) AS ht,
           round(l.quantite * l.prix_unitaire * l.tva_rate / 100, 2) AS tva_montant
      FROM quote.ligne l
     WHERE l.devis_id = p_id
     ORDER BY l.sort_order, l.id
  LOOP
    v_rows := v_rows || ARRAY[
      pgv.esc(r.description),
      r.quantite::text,
      r.unite,
      to_char(r.prix_unitaire, 'FM999 990.00'),
      r.tva_rate::text || ' %',
      to_char(r.ht, 'FM999 990.00'),
      CASE WHEN d.statut = 'brouillon'
        THEN pgv.action('post_ligne_supprimer', 'Suppr.', jsonb_build_object('id', r.id), 'Supprimer cette ligne ?', 'danger')
        ELSE ''
      END
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := v_body || pgv.empty('Aucune ligne', 'Ajoutez des lignes à ce devis.');
  ELSE
    v_body := v_body || pgv.md_table(ARRAY['Description', 'Qté', 'Unité', 'PU HT', 'TVA', 'Montant HT', ''], v_rows);
  END IF;

  -- Formulaire ajout ligne (brouillon uniquement)
  IF d.statut = 'brouillon' THEN
    v_body := v_body || '<details><summary>Ajouter une ligne</summary>'
      || '<form data-rpc="post_ligne_ajouter">'
      || '<input type="hidden" name="devis_id" value="' || p_id || '">'
      || pgv.select_search('article_id', 'Article (catalogue)', 'quote.article_search', 'Chercher un article...')
      || '<label>Description <input type="text" name="description" placeholder="Renseignée depuis l''article si sélectionné"></label>'
      || '<div class="grid">'
      || '<label>Quantité <input type="number" name="quantite" value="1" step="0.01" min="0.01" required></label>'
      || '<label>Unité <select name="unite">'
      || '<option value="u">Unité</option><option value="h">Heure</option>'
      || '<option value="m">Mètre</option><option value="m2">m²</option>'
      || '<option value="m3">m³</option><option value="forfait">Forfait</option>'
      || '</select></label>'
      || '</div><div class="grid">'
      || '<label>Prix unitaire HT <input type="number" name="prix_unitaire" step="0.01" min="0"></label>'
      || '<label>TVA <select name="tva_rate">'
      || '<option value="20.00">20 %</option><option value="10.00">10 %</option>'
      || '<option value="5.50">5,5 %</option><option value="0.00">0 %</option>'
      || '</select></label>'
      || '</div>'
      || '<button type="submit">Ajouter</button>'
      || '</form></details>';
  END IF;

  -- Actions selon statut
  v_body := v_body || '<div class="grid">';
  IF d.statut = 'brouillon' THEN
    v_body := v_body
      || format('<a href="%s" role="button" class="outline">Modifier</a>', pgv.call_ref('get_devis_form', jsonb_build_object('p_id', p_id)))
      || pgv.action('post_devis_envoyer', 'Envoyer', jsonb_build_object('id', p_id), 'Marquer ce devis comme envoyé ?')
      || pgv.action('post_devis_supprimer', 'Supprimer', jsonb_build_object('id', p_id), 'Supprimer ce brouillon ?', 'danger');
  ELSIF d.statut = 'envoye' THEN
    v_body := v_body
      || pgv.action('post_devis_accepter', 'Accepter', jsonb_build_object('id', p_id), 'Marquer ce devis comme accepté ?')
      || pgv.action('post_devis_refuser', 'Refuser', jsonb_build_object('id', p_id), 'Marquer ce devis comme refusé ?', 'danger');
  ELSIF d.statut = 'accepte' THEN
    v_body := v_body
      || pgv.action('post_devis_facturer', 'Créer la facture', jsonb_build_object('id', p_id), 'Créer une facture depuis ce devis ?');
  END IF;
  -- Dupliquer disponible sur tous les statuts
  v_body := v_body
    || pgv.action('post_devis_dupliquer', 'Dupliquer', jsonb_build_object('id', p_id), 'Dupliquer ce devis en brouillon ?');
  v_body := v_body || '</div>';

  IF d.notes <> '' THEN
    v_body := v_body || '<h4>Notes</h4><p>' || pgv.esc(d.notes) || '</p>';
  END IF;

  -- Mentions légales
  v_body := v_body || quote._mentions_html();

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION quote.get_devis(integer) IS 'Liste des devis (sans p_id) ou détail d''un devis (avec p_id)';

CREATE OR REPLACE FUNCTION quote.get_devis_form(p_id integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_body text;
  d record;
  v_objet text := '';
  v_validite int := 30;
  v_notes text := '';
BEGIN
  IF p_id IS NOT NULL THEN
    SELECT * INTO d FROM quote.devis WHERE id = p_id;
    IF NOT FOUND THEN RETURN pgv.empty('Devis introuvable'); END IF;
    IF d.statut <> 'brouillon' THEN
      RETURN pgv.empty('Modification impossible', 'Seuls les brouillons sont modifiables.');
    END IF;
    v_objet := pgv.esc(d.objet);
    v_validite := d.validite_jours;
    v_notes := pgv.esc(d.notes);
  END IF;

  v_body := pgv.breadcrumb(VARIADIC ARRAY[
    'Devis', pgv.call_ref('get_devis'),
    CASE WHEN p_id IS NOT NULL THEN 'Modifier' ELSE 'Nouveau devis' END
  ]);

  v_body := v_body || '<form data-rpc="post_devis_save">';
  IF p_id IS NOT NULL THEN
    v_body := v_body || '<input type="hidden" name="id" value="' || p_id || '">';
  END IF;

  v_body := v_body
    || '<label>Client <select name="client_id" required>'
    || '<option value="">— Choisir —</option>'
    || quote._client_options()
    || '</select></label>';

  IF p_id IS NOT NULL THEN
    v_body := replace(v_body,
      'value="' || d.client_id || '">',
      'value="' || d.client_id || '" selected>');
  END IF;

  v_body := v_body
    || '<label>Objet <input type="text" name="objet" value="' || v_objet || '" required></label>'
    || '<label>Validité (jours) <input type="number" name="validite_jours" value="' || v_validite || '" min="1"></label>'
    || '<label>Notes <textarea name="notes">' || v_notes || '</textarea></label>'
    || '<button type="submit">' || CASE WHEN p_id IS NOT NULL THEN 'Mettre à jour' ELSE 'Créer le devis' END || '</button>'
    || '</form>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION quote.get_devis_form(integer) IS 'Formulaire création/édition d''un devis';

CREATE OR REPLACE FUNCTION quote.get_facture(p_id integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_rows text[];
  v_body text;
  v_ht numeric(12,2);
  v_tva numeric(12,2);
  v_ttc numeric(12,2);
  v_days_since int;
  f record;
  r record;
BEGIN
  -- List mode
  IF p_id IS NULL THEN
    v_rows := ARRAY[]::text[];
    FOR r IN
      SELECT fa.id, fa.numero, fa.client_id, c.name AS client, fa.objet, fa.statut,
             quote._total_ttc(NULL, fa.id) AS ttc, fa.created_at
        FROM quote.facture fa
        JOIN crm.client c ON c.id = fa.client_id
       ORDER BY fa.created_at DESC
    LOOP
      v_rows := v_rows || ARRAY[
        format('<a href="%s">%s</a>', pgv.call_ref('get_facture', jsonb_build_object('p_id', r.id)), pgv.esc(r.numero)),
        format('<a href="/crm/client?p_id=%s">%s</a>', r.client_id, pgv.esc(r.client)),
        pgv.esc(r.objet),
        quote._statut_badge(r.statut),
        to_char(r.ttc, 'FM999 990.00') || ' EUR',
        to_char(r.created_at, 'DD/MM/YYYY')
      ];
    END LOOP;

    IF array_length(v_rows, 1) IS NULL THEN
      v_body := pgv.empty('Aucune facture', 'Les factures apparaîtront ici.');
    ELSE
      v_body := pgv.md_table(ARRAY['Numéro', 'Client', 'Objet', 'Statut', 'Total TTC', 'Date'], v_rows);
    END IF;

    v_body := v_body || format('<p><a href="%s" role="button">Nouvelle facture</a></p>', pgv.call_ref('get_facture_form'));
    RETURN pgv.breadcrumb(VARIADIC ARRAY['Factures']) || v_body;
  END IF;

  -- Detail mode
  SELECT fa.*, c.name AS client_name,
         dv.numero AS devis_numero, dv.id AS devis_pk
    INTO f
    FROM quote.facture fa
    JOIN crm.client c ON c.id = fa.client_id
    LEFT JOIN quote.devis dv ON dv.id = fa.devis_id
   WHERE fa.id = p_id;

  IF NOT FOUND THEN
    RETURN pgv.empty('Facture introuvable');
  END IF;

  v_ht := quote._total_ht(NULL, p_id);
  v_tva := quote._total_tva(NULL, p_id);
  v_ttc := v_ht + v_tva;

  v_body := pgv.breadcrumb(VARIADIC ARRAY[
    'Factures', pgv.call_ref('get_facture'),
    f.numero
  ]);

  -- Badge relance si envoyée > 30j
  v_days_since := extract(day FROM now() - f.created_at)::int;

  v_body := v_body || pgv.dl(VARIADIC ARRAY[
    'Numéro', f.numero,
    'Client', format('<a href="/crm/client?p_id=%s">%s</a>', f.client_id, pgv.esc(f.client_name)),
    'Objet', pgv.esc(f.objet),
    'Statut', quote._statut_badge(f.statut)
      || CASE WHEN f.statut = 'envoyee' AND v_days_since > 30
           THEN ' ' || pgv.badge('Relance', 'danger')
           ELSE ''
         END,
    'Devis', CASE WHEN f.devis_numero IS NOT NULL
      THEN format('<a href="%s">%s</a>', pgv.call_ref('get_devis', jsonb_build_object('p_id', f.devis_pk)), pgv.esc(f.devis_numero))
      ELSE 'Facture directe'
    END,
    'Date', to_char(f.created_at, 'DD/MM/YYYY'),
    'Payée le', CASE WHEN f.paid_at IS NOT NULL THEN to_char(f.paid_at, 'DD/MM/YYYY') ELSE '—' END,
    'Total HT', to_char(v_ht, 'FM999 990.00') || ' EUR',
    'Total TVA', to_char(v_tva, 'FM999 990.00') || ' EUR',
    'Total TTC', to_char(v_ttc, 'FM999 990.00') || ' EUR'
  ]);

  -- Lignes
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT l.id, l.description, l.quantite, l.unite, l.prix_unitaire, l.tva_rate,
           round(l.quantite * l.prix_unitaire, 2) AS ht
      FROM quote.ligne l
     WHERE l.facture_id = p_id
     ORDER BY l.sort_order, l.id
  LOOP
    v_rows := v_rows || ARRAY[
      pgv.esc(r.description),
      r.quantite::text,
      r.unite,
      to_char(r.prix_unitaire, 'FM999 990.00'),
      r.tva_rate::text || ' %',
      to_char(r.ht, 'FM999 990.00'),
      CASE WHEN f.statut = 'brouillon'
        THEN pgv.action('post_ligne_supprimer', 'Suppr.', jsonb_build_object('id', r.id), 'Supprimer cette ligne ?', 'danger')
        ELSE ''
      END
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := v_body || pgv.empty('Aucune ligne');
  ELSE
    v_body := v_body || pgv.md_table(ARRAY['Description', 'Qté', 'Unité', 'PU HT', 'TVA', 'Montant HT', ''], v_rows);
  END IF;

  -- Formulaire ajout ligne (brouillon uniquement)
  IF f.statut = 'brouillon' THEN
    v_body := v_body || '<details><summary>Ajouter une ligne</summary>'
      || '<form data-rpc="post_ligne_ajouter">'
      || '<input type="hidden" name="facture_id" value="' || p_id || '">'
      || pgv.select_search('article_id', 'Article (catalogue)', 'quote.article_search', 'Chercher un article...')
      || '<label>Description <input type="text" name="description" placeholder="Renseignée depuis l''article si sélectionné"></label>'
      || '<div class="grid">'
      || '<label>Quantité <input type="number" name="quantite" value="1" step="0.01" min="0.01" required></label>'
      || '<label>Unité <select name="unite">'
      || '<option value="u">Unité</option><option value="h">Heure</option>'
      || '<option value="m">Mètre</option><option value="m2">m²</option>'
      || '<option value="m3">m³</option><option value="forfait">Forfait</option>'
      || '</select></label>'
      || '</div><div class="grid">'
      || '<label>Prix unitaire HT <input type="number" name="prix_unitaire" step="0.01" min="0"></label>'
      || '<label>TVA <select name="tva_rate">'
      || '<option value="20.00">20 %</option><option value="10.00">10 %</option>'
      || '<option value="5.50">5,5 %</option><option value="0.00">0 %</option>'
      || '</select></label>'
      || '</div>'
      || '<button type="submit">Ajouter</button>'
      || '</form></details>';
  END IF;

  -- Actions selon statut
  v_body := v_body || '<div class="grid">';
  IF f.statut = 'brouillon' THEN
    v_body := v_body
      || format('<a href="%s" role="button" class="outline">Modifier</a>', pgv.call_ref('get_facture_form', jsonb_build_object('p_id', p_id)))
      || pgv.action('post_facture_envoyer', 'Envoyer', jsonb_build_object('id', p_id), 'Marquer cette facture comme envoyée ?')
      || pgv.action('post_facture_supprimer', 'Supprimer', jsonb_build_object('id', p_id), 'Supprimer ce brouillon ?', 'danger');
  ELSIF f.statut = 'envoyee' THEN
    v_body := v_body
      || pgv.action('post_facture_payer', 'Marquer payée', jsonb_build_object('id', p_id), 'Marquer cette facture comme payée ?');
    IF v_days_since > 30 THEN
      v_body := v_body
        || pgv.action('post_facture_relancer', 'Relancer', jsonb_build_object('id', p_id), 'Marquer cette facture en relance ?', 'danger');
    END IF;
  END IF;
  v_body := v_body || '</div>';

  IF f.notes <> '' THEN
    v_body := v_body || '<h4>Notes</h4><p>' || pgv.esc(f.notes) || '</p>';
  END IF;

  -- Mentions légales
  v_body := v_body || quote._mentions_html();

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION quote.get_facture(integer) IS 'Liste des factures (sans p_id) ou détail d''une facture (avec p_id)';

CREATE OR REPLACE FUNCTION quote.get_facture_form(p_id integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_body text;
  f record;
  v_objet text := '';
  v_notes text := '';
BEGIN
  IF p_id IS NOT NULL THEN
    SELECT * INTO f FROM quote.facture WHERE id = p_id;
    IF NOT FOUND THEN RETURN pgv.empty('Facture introuvable'); END IF;
    IF f.statut <> 'brouillon' THEN
      RETURN pgv.empty('Modification impossible', 'Seuls les brouillons sont modifiables.');
    END IF;
    v_objet := pgv.esc(f.objet);
    v_notes := pgv.esc(f.notes);
  END IF;

  v_body := pgv.breadcrumb(VARIADIC ARRAY[
    'Factures', pgv.call_ref('get_facture'),
    CASE WHEN p_id IS NOT NULL THEN 'Modifier' ELSE 'Nouvelle facture' END
  ]);

  v_body := v_body || '<form data-rpc="post_facture_save">';
  IF p_id IS NOT NULL THEN
    v_body := v_body || '<input type="hidden" name="id" value="' || p_id || '">';
  END IF;

  v_body := v_body
    || '<label>Client <select name="client_id" required>'
    || '<option value="">— Choisir —</option>'
    || quote._client_options()
    || '</select></label>';

  IF p_id IS NOT NULL THEN
    v_body := replace(v_body,
      'value="' || f.client_id || '">',
      'value="' || f.client_id || '" selected>');
  END IF;

  v_body := v_body
    || '<label>Objet <input type="text" name="objet" value="' || v_objet || '" required></label>'
    || '<label>Notes <textarea name="notes">' || v_notes || '</textarea></label>'
    || '<button type="submit">' || CASE WHEN p_id IS NOT NULL THEN 'Mettre à jour' ELSE 'Créer la facture' END || '</button>'
    || '</form>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION quote.get_facture_form(integer) IS 'Formulaire création/édition d''une facture directe';

CREATE OR REPLACE FUNCTION quote.get_index()
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_devis_en_cours int;
  v_factures_impayees int;
  v_ca_mois numeric(12,2);
  v_taux_acceptation text;
  v_nb_total int;
  v_nb_accepte int;
  v_body text;
  v_rows_d text[];
  v_rows_f text[];
  r record;
BEGIN
  -- Stats
  SELECT count(*)::int INTO v_devis_en_cours
    FROM quote.devis WHERE statut IN ('brouillon', 'envoye');

  SELECT count(*)::int INTO v_factures_impayees
    FROM quote.facture WHERE statut = 'envoyee';

  SELECT coalesce(sum(quote._total_ttc(NULL, f.id)), 0) INTO v_ca_mois
    FROM quote.facture f
   WHERE f.statut = 'payee'
     AND f.paid_at >= date_trunc('month', now());

  SELECT count(*)::int, count(*) FILTER (WHERE statut = 'accepte')::int
    INTO v_nb_total, v_nb_accepte
    FROM quote.devis WHERE statut IN ('accepte', 'refuse');

  IF v_nb_total > 0 THEN
    v_taux_acceptation := round(v_nb_accepte * 100.0 / v_nb_total)::text || ' %';
  ELSE
    v_taux_acceptation := '—';
  END IF;

  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.stat('Devis en cours', v_devis_en_cours::text),
    pgv.stat('Factures impayées', v_factures_impayees::text),
    pgv.stat('CA du mois', to_char(v_ca_mois, 'FM999 990.00') || ' EUR'),
    pgv.stat('Taux acceptation', v_taux_acceptation)
  ]);

  -- Tab 1: Devis récents
  v_rows_d := ARRAY[]::text[];
  FOR r IN
    SELECT d.id, d.numero, d.client_id, c.name AS client, d.objet, d.statut,
           quote._total_ttc(d.id, NULL) AS ttc, d.created_at
      FROM quote.devis d
      JOIN crm.client c ON c.id = d.client_id
     ORDER BY d.created_at DESC LIMIT 10
  LOOP
    v_rows_d := v_rows_d || ARRAY[
      format('<a href="%s">%s</a>', pgv.call_ref('get_devis', jsonb_build_object('p_id', r.id)), pgv.esc(r.numero)),
      format('<a href="/crm/client?p_id=%s">%s</a>', r.client_id, pgv.esc(r.client)),
      pgv.esc(r.objet),
      quote._statut_badge(r.statut),
      to_char(r.ttc, 'FM999 990.00') || ' EUR',
      to_char(r.created_at, 'DD/MM/YYYY')
    ];
  END LOOP;

  -- Tab 2: Factures récentes
  v_rows_f := ARRAY[]::text[];
  FOR r IN
    SELECT f.id, f.numero, f.client_id, c.name AS client, f.objet, f.statut,
           quote._total_ttc(NULL, f.id) AS ttc, f.created_at
      FROM quote.facture f
      JOIN crm.client c ON c.id = f.client_id
     ORDER BY f.created_at DESC LIMIT 10
  LOOP
    v_rows_f := v_rows_f || ARRAY[
      format('<a href="%s">%s</a>', pgv.call_ref('get_facture', jsonb_build_object('p_id', r.id)), pgv.esc(r.numero)),
      format('<a href="/crm/client?p_id=%s">%s</a>', r.client_id, pgv.esc(r.client)),
      pgv.esc(r.objet),
      quote._statut_badge(r.statut),
      to_char(r.ttc, 'FM999 990.00') || ' EUR',
      to_char(r.created_at, 'DD/MM/YYYY')
    ];
  END LOOP;

  v_body := v_body || pgv.tabs(VARIADIC ARRAY[
    'Devis récents',
    CASE WHEN array_length(v_rows_d, 1) IS NULL
      THEN pgv.empty('Aucun devis', 'Créez votre premier devis pour commencer.')
      ELSE pgv.md_table(ARRAY['Numéro', 'Client', 'Objet', 'Statut', 'Total TTC', 'Date'], v_rows_d)
    END,
    'Factures récentes',
    CASE WHEN array_length(v_rows_f, 1) IS NULL
      THEN pgv.empty('Aucune facture')
      ELSE pgv.md_table(ARRAY['Numéro', 'Client', 'Objet', 'Statut', 'Total TTC', 'Date'], v_rows_f)
    END
  ]);

  v_body := v_body || '<p>'
    || format('<a href="%s" role="button">Nouveau devis</a>', pgv.call_ref('get_devis_form'))
    || ' '
    || format('<a href="%s" role="button" class="outline">Nouvelle facture</a>', pgv.call_ref('get_facture_form'))
    || '</p>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION quote.get_index() IS 'Dashboard quote : stats KPI + tabs devis/factures récents';

CREATE OR REPLACE FUNCTION quote.nav_items()
 RETURNS jsonb
 LANGUAGE sql
AS $function$
  SELECT '[{"href":"/","label":"Dashboard","icon":"home"},{"href":"/devis","label":"Devis","icon":"file-text"},{"href":"/facture","label":"Factures","icon":"receipt"}]'::jsonb;
$function$;
COMMENT ON FUNCTION quote.nav_items() IS 'Navigation items for Quote module';

CREATE OR REPLACE FUNCTION quote.post_devis_accepter(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int := (p_data->>'id')::int;
  v_statut text;
BEGIN
  SELECT statut INTO v_statut FROM quote.devis WHERE id = v_id;
  IF v_statut IS NULL THEN RAISE EXCEPTION 'Devis introuvable'; END IF;
  IF v_statut <> 'envoye' THEN RAISE EXCEPTION 'Transition invalide: % -> accepte', v_statut; END IF;

  UPDATE quote.devis SET statut = 'accepte' WHERE id = v_id;

  RETURN '<template data-toast="success">Devis accepté</template>'
    || '<template data-redirect="' || pgv.call_ref('get_devis', jsonb_build_object('p_id', v_id)) || '"></template>';
END;
$function$;
COMMENT ON FUNCTION quote.post_devis_accepter(jsonb) IS 'Marquer un devis envoyé comme accepté';

CREATE OR REPLACE FUNCTION quote.post_devis_dupliquer(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_src_id int := (p_data->>'id')::int;
  v_new_id int;
  v_numero text;
  d record;
BEGIN
  SELECT * INTO d FROM quote.devis WHERE id = v_src_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'Devis introuvable'; END IF;

  v_numero := quote._next_numero('DEV');

  INSERT INTO quote.devis (numero, client_id, objet, validite_jours, notes)
  VALUES (v_numero, d.client_id, d.objet, d.validite_jours, d.notes)
  RETURNING id INTO v_new_id;

  INSERT INTO quote.ligne (devis_id, sort_order, description, quantite, unite, prix_unitaire, tva_rate)
  SELECT v_new_id, sort_order, description, quantite, unite, prix_unitaire, tva_rate
    FROM quote.ligne WHERE devis_id = v_src_id
   ORDER BY sort_order, id;

  RETURN '<template data-toast="success">Devis dupliqué : ' || pgv.esc(v_numero) || '</template>'
    || '<template data-redirect="' || pgv.call_ref('get_devis', jsonb_build_object('p_id', v_new_id)) || '"></template>';
END;
$function$;
COMMENT ON FUNCTION quote.post_devis_dupliquer(jsonb) IS 'Dupliquer un devis existant (header + lignes) en brouillon avec nouveau numéro';

