CREATE OR REPLACE FUNCTION quote.post_facture_payer(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int := (p_data->>'id')::int;
  v_statut text;
BEGIN
  SELECT statut INTO v_statut FROM quote.facture WHERE id = v_id;
  IF v_statut IS NULL THEN RAISE EXCEPTION 'Facture introuvable'; END IF;
  IF v_statut <> 'envoyee' THEN RAISE EXCEPTION 'Transition invalide: % -> payee', v_statut; END IF;

  UPDATE quote.facture SET statut = 'payee', paid_at = now() WHERE id = v_id;

  RETURN '<template data-toast="success">Facture marquée comme payée</template>'
    || '<template data-redirect="' || pgv.call_ref('get_facture', jsonb_build_object('p_id', v_id)) || '"></template>';
END;
$function$;
COMMENT ON FUNCTION quote.post_facture_payer(jsonb) IS 'Marquer une facture envoyée comme payée';

CREATE OR REPLACE FUNCTION quote.post_facture_relancer(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int := (p_data->>'p_id')::int;
  v_statut text;
  v_days int;
BEGIN
  SELECT statut, extract(day FROM now() - created_at)::int
    INTO v_statut, v_days
    FROM quote.facture WHERE id = v_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Facture #% introuvable', v_id;
  END IF;

  IF v_statut <> 'envoyee' THEN
    RAISE EXCEPTION 'Seule une facture envoyee peut etre relancee (statut actuel: %)', v_statut;
  END IF;

  IF v_days <= 30 THEN
    RAISE EXCEPTION 'Relance possible uniquement apres 30 jours (actuellement: % jours)', v_days;
  END IF;

  UPDATE quote.facture
     SET statut = 'relance',
         notes = notes || E'\n[Relance ' || to_char(now(), 'DD/MM/YYYY') || ']'
   WHERE id = v_id;

  RETURN '<template data-toast="success">Relance enregistree pour la facture</template>'
      || '<template data-redirect="/quote/facture?p_id=' || v_id || '"></template>';
END;
$function$;
COMMENT ON FUNCTION quote.post_facture_relancer(jsonb) IS 'Mark an overdue invoice as relancee (payment reminder sent)';

CREATE OR REPLACE FUNCTION quote.post_facture_save(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int;
  v_numero text;
BEGIN
  IF p_data->>'id' IS NOT NULL THEN
    v_id := (p_data->>'id')::int;
    IF NOT EXISTS (SELECT 1 FROM quote.facture WHERE id = v_id AND statut = 'brouillon') THEN
      RAISE EXCEPTION 'Seuls les brouillons sont modifiables';
    END IF;
    UPDATE quote.facture SET
      client_id = (p_data->>'client_id')::int,
      objet = p_data->>'objet',
      notes = coalesce(p_data->>'notes', '')
    WHERE id = v_id;
  ELSE
    v_numero := quote._next_numero('FAC');
    INSERT INTO quote.facture (numero, client_id, objet, notes)
    VALUES (
      v_numero,
      (p_data->>'client_id')::int,
      p_data->>'objet',
      coalesce(p_data->>'notes', '')
    ) RETURNING id INTO v_id;
  END IF;

  RETURN '<template data-toast="success">Facture enregistrée</template>'
    || '<template data-redirect="' || pgv.call_ref('get_facture', jsonb_build_object('p_id', v_id)) || '"></template>';
END;
$function$;
COMMENT ON FUNCTION quote.post_facture_save(jsonb) IS 'Créer ou mettre à jour une facture (brouillon uniquement)';

CREATE OR REPLACE FUNCTION quote.post_facture_supprimer(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int := (p_data->>'id')::int;
  v_statut text;
BEGIN
  SELECT statut INTO v_statut FROM quote.facture WHERE id = v_id;
  IF v_statut IS NULL THEN RAISE EXCEPTION 'Facture introuvable'; END IF;
  IF v_statut <> 'brouillon' THEN RAISE EXCEPTION 'Seuls les brouillons peuvent être supprimés'; END IF;

  DELETE FROM quote.facture WHERE id = v_id;

  RETURN '<template data-toast="success">Facture supprimée</template>'
    || '<template data-redirect="' || pgv.call_ref('get_facture') || '"></template>';
END;
$function$;
COMMENT ON FUNCTION quote.post_facture_supprimer(jsonb) IS 'Supprimer une facture brouillon';

CREATE OR REPLACE FUNCTION quote.post_ligne_ajouter(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_devis_id int;
  v_facture_id int;
  v_redirect text;
  v_article_id int;
  v_description text;
  v_prix_unitaire numeric;
  v_tva_rate numeric;
  v_unite text;
  v_art record;
BEGIN
  v_devis_id := (p_data->>'devis_id')::int;
  v_facture_id := (p_data->>'facture_id')::int;
  v_article_id := (p_data->>'article_id')::int;

  -- Vérifier que le parent est brouillon
  IF v_devis_id IS NOT NULL THEN
    IF NOT EXISTS (SELECT 1 FROM quote.devis WHERE id = v_devis_id AND statut = 'brouillon') THEN
      RAISE EXCEPTION 'Lignes modifiables uniquement sur un brouillon';
    END IF;
    v_redirect := pgv.call_ref('get_devis', jsonb_build_object('p_id', v_devis_id));
  ELSIF v_facture_id IS NOT NULL THEN
    IF NOT EXISTS (SELECT 1 FROM quote.facture WHERE id = v_facture_id AND statut = 'brouillon') THEN
      RAISE EXCEPTION 'Lignes modifiables uniquement sur un brouillon';
    END IF;
    v_redirect := pgv.call_ref('get_facture', jsonb_build_object('p_id', v_facture_id));
  ELSE
    RAISE EXCEPTION 'devis_id ou facture_id requis';
  END IF;

  -- Lookup article si sélectionné (catalog > stock)
  IF v_article_id IS NOT NULL THEN
    -- Priority 1: catalog.article
    IF EXISTS (
      SELECT 1 FROM pg_namespace n
      JOIN pg_class c ON c.relnamespace = n.oid AND c.relname = 'article'
     WHERE n.nspname = 'catalog'
    ) THEN
      EXECUTE
        'SELECT designation, prix_vente AS prix_achat, unite, tva
         FROM catalog.article WHERE id = $1 AND actif'
      INTO v_art USING v_article_id;
    END IF;
    -- Priority 2: stock.article fallback
    IF v_art.designation IS NULL AND EXISTS (
      SELECT 1 FROM pg_namespace n
      JOIN pg_class c ON c.relnamespace = n.oid AND c.relname = 'article'
     WHERE n.nspname = 'stock'
    ) THEN
      EXECUTE
        'SELECT designation, prix_achat, unite, NULL::numeric AS tva
         FROM stock.article WHERE id = $1 AND active = true'
      INTO v_art USING v_article_id;
    END IF;
  END IF;

  -- Resolve values: form > article > defaults
  v_description := coalesce(
    nullif(trim(p_data->>'description'), ''),
    v_art.designation,
    'Ligne sans description'
  );
  v_prix_unitaire := coalesce(
    nullif((p_data->>'prix_unitaire')::numeric, 0),
    v_art.prix_achat,
    0
  );
  v_unite := coalesce(
    nullif(p_data->>'unite', ''),
    v_art.unite,
    'u'
  );
  v_tva_rate := coalesce((p_data->>'tva_rate')::numeric, v_art.tva, 20.00);

  INSERT INTO quote.ligne (devis_id, facture_id, description, quantite, unite, prix_unitaire, tva_rate)
  VALUES (
    v_devis_id,
    v_facture_id,
    v_description,
    coalesce((p_data->>'quantite')::numeric, 1),
    v_unite,
    v_prix_unitaire,
    v_tva_rate
  );

  RETURN '<template data-toast="success">Ligne ajoutée</template>'
    || '<template data-redirect="' || v_redirect || '"></template>';
END;
$function$;
COMMENT ON FUNCTION quote.post_ligne_ajouter(jsonb) IS 'Ajouter une ligne à un devis ou facture brouillon';

CREATE OR REPLACE FUNCTION quote.post_ligne_supprimer(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_ligne_id int := (p_data->>'id')::int;
  v_redirect text;
  r record;
BEGIN
  SELECT l.devis_id, l.facture_id INTO r
    FROM quote.ligne l WHERE l.id = v_ligne_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'Ligne introuvable'; END IF;

  -- Vérifier que le parent est brouillon
  IF r.devis_id IS NOT NULL THEN
    IF NOT EXISTS (SELECT 1 FROM quote.devis WHERE id = r.devis_id AND statut = 'brouillon') THEN
      RAISE EXCEPTION 'Lignes modifiables uniquement sur un brouillon';
    END IF;
    v_redirect := pgv.call_ref('get_devis', jsonb_build_object('p_id', r.devis_id));
  ELSE
    IF NOT EXISTS (SELECT 1 FROM quote.facture WHERE id = r.facture_id AND statut = 'brouillon') THEN
      RAISE EXCEPTION 'Lignes modifiables uniquement sur un brouillon';
    END IF;
    v_redirect := pgv.call_ref('get_facture', jsonb_build_object('p_id', r.facture_id));
  END IF;

  DELETE FROM quote.ligne WHERE id = v_ligne_id;

  RETURN '<template data-toast="success">Ligne supprimée</template>'
    || '<template data-redirect="' || v_redirect || '"></template>';
END;
$function$;
COMMENT ON FUNCTION quote.post_ligne_supprimer(jsonb) IS 'Supprimer une ligne (parent brouillon uniquement)';

GRANT USAGE ON SCHEMA quote TO web_anon;
GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA quote TO web_anon;

-- Schema: quote_ut
CREATE SCHEMA IF NOT EXISTS quote_ut;

CREATE OR REPLACE FUNCTION quote_ut.test__next_numero()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN QUERY SELECT * FROM quote_ut.test_next_numero();
  -- Branche ELSE: préfixe invalide
  RETURN NEXT throws_ok(
    'SELECT quote._next_numero(''XXX'')',
    'Préfixe invalide: XXX'
  );
END;
$function$;
COMMENT ON FUNCTION quote_ut.test__next_numero() IS 'Test numérotation séquentielle + branche préfixe invalide';

CREATE OR REPLACE FUNCTION quote_ut.test_article_search()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_result jsonb;
  v_item jsonb;
BEGIN
  -- Test: returns jsonb array (not null)
  v_result := quote.article_search('');
  RETURN NEXT ok(v_result IS NOT NULL, 'search returns non-null');
  RETURN NEXT ok(jsonb_typeof(v_result) = 'array', 'search returns array');

  -- Test: with search filter
  v_result := quote.article_search('bois');
  RETURN NEXT ok(jsonb_typeof(v_result) = 'array', 'filtered search returns array');

  -- Test: items have required keys (value, label)
  IF jsonb_array_length(v_result) > 0 THEN
    v_item := v_result->0;
    RETURN NEXT ok(v_item ? 'value', 'item has value key');
    RETURN NEXT ok(v_item ? 'label', 'item has label key');
    RETURN NEXT ok(v_item ? 'detail', 'item has detail key');
  ELSE
    RETURN NEXT skip('no articles in stock, skipping structure checks');
    RETURN NEXT skip('no articles in stock');
    RETURN NEXT skip('no articles in stock');
  END IF;

  -- Test: nonsense search returns empty array
  v_result := quote.article_search('zzzzxyznonexistent');
  RETURN NEXT is(jsonb_array_length(v_result), 0, 'nonsense search returns empty');
END;
$function$;
COMMENT ON FUNCTION quote_ut.test_article_search() IS 'Test article_search returns valid jsonb for pgv.select_search()';

CREATE OR REPLACE FUNCTION quote_ut.test_delete_constraints()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int;
  v_client_id int;
BEGIN
  UPDATE project.chantier SET devis_id = NULL WHERE devis_id IS NOT NULL;
  DELETE FROM quote.ligne;
  DELETE FROM quote.facture;
  DELETE FROM quote.devis;

  SELECT id INTO v_client_id FROM crm.client LIMIT 1;

  -- Devis non-brouillon ne peut pas être supprimé
  PERFORM quote.post_devis_save(jsonb_build_object('client_id', v_client_id, 'objet', 'Test delete'));
  SELECT id INTO v_id FROM quote.devis ORDER BY id DESC LIMIT 1;
  PERFORM quote.post_devis_envoyer(jsonb_build_object('id', v_id));

  RETURN NEXT throws_ok(
    format('SELECT quote.post_devis_supprimer(''{"id":%s}''::jsonb)', v_id),
    'Seuls les brouillons peuvent être supprimés'
  );

  -- Devis brouillon peut être supprimé
  PERFORM quote.post_devis_save(jsonb_build_object('client_id', v_client_id, 'objet', 'Brouillon'));
  SELECT id INTO v_id FROM quote.devis WHERE statut = 'brouillon' ORDER BY id DESC LIMIT 1;
  PERFORM quote.post_devis_supprimer(jsonb_build_object('id', v_id));
  RETURN NEXT is((SELECT count(*)::int FROM quote.devis WHERE id = v_id), 0, 'Brouillon supprimé');

  -- Facture envoyée ne peut pas être supprimée (immutabilité légale)
  PERFORM quote.post_facture_save(jsonb_build_object('client_id', v_client_id, 'objet', 'Test immuable'));
  SELECT id INTO v_id FROM quote.facture ORDER BY id DESC LIMIT 1;
  PERFORM quote.post_facture_envoyer(jsonb_build_object('id', v_id));

  RETURN NEXT throws_ok(
    format('SELECT quote.post_facture_supprimer(''{"id":%s}''::jsonb)', v_id),
    'Seuls les brouillons peuvent être supprimés'
  );

  UPDATE project.chantier SET devis_id = NULL WHERE devis_id IS NOT NULL;
  DELETE FROM quote.ligne;
  DELETE FROM quote.facture;
  DELETE FROM quote.devis;
END;
$function$;
COMMENT ON FUNCTION quote_ut.test_delete_constraints() IS 'Test contraintes de suppression (brouillon only, immutabilité facture)';

CREATE OR REPLACE FUNCTION quote_ut.test_devis_facturer()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_devis_id int;
  v_facture_id int;
  v_client_id int;
  v_nb_lignes_d int;
  v_nb_lignes_f int;
  v_ttc_d numeric(12,2);
  v_ttc_f numeric(12,2);
BEGIN
  UPDATE project.chantier SET devis_id = NULL WHERE devis_id IS NOT NULL;
  DELETE FROM quote.ligne;
  DELETE FROM quote.facture;
  DELETE FROM quote.devis;

  SELECT id INTO v_client_id FROM crm.client LIMIT 1;

  -- Créer devis + lignes
  PERFORM quote.post_devis_save(jsonb_build_object('client_id', v_client_id, 'objet', 'Travaux salle de bain'));
  SELECT id INTO v_devis_id FROM quote.devis ORDER BY id DESC LIMIT 1;

  PERFORM quote.post_ligne_ajouter(jsonb_build_object('devis_id', v_devis_id, 'description', 'Main oeuvre', 'quantite', 8, 'unite', 'h', 'prix_unitaire', 45, 'tva_rate', 10));
  PERFORM quote.post_ligne_ajouter(jsonb_build_object('devis_id', v_devis_id, 'description', 'Fournitures', 'quantite', 1, 'unite', 'forfait', 'prix_unitaire', 350, 'tva_rate', 20));

  -- Facturer un brouillon -> erreur
  RETURN NEXT throws_ok(
    format('SELECT quote.post_devis_facturer(''{"id":%s}''::jsonb)', v_devis_id),
    'Seuls les devis acceptés peuvent être facturés'
  );

  -- Cycle: envoyer -> accepter -> facturer
  PERFORM quote.post_devis_envoyer(jsonb_build_object('id', v_devis_id));
  PERFORM quote.post_devis_accepter(jsonb_build_object('id', v_devis_id));
  PERFORM quote.post_devis_facturer(jsonb_build_object('id', v_devis_id));

  SELECT id INTO v_facture_id FROM quote.facture WHERE devis_id = v_devis_id;
  RETURN NEXT isnt(v_facture_id, NULL, 'Facture créée depuis devis');

  -- Vérifier que les lignes ont été copiées
  SELECT count(*)::int INTO v_nb_lignes_d FROM quote.ligne WHERE devis_id = v_devis_id;
  SELECT count(*)::int INTO v_nb_lignes_f FROM quote.ligne WHERE facture_id = v_facture_id;
  RETURN NEXT is(v_nb_lignes_f, v_nb_lignes_d, 'Lignes copiées dans la facture');

  -- Vérifier montants identiques
  SELECT sum(round(quantite * prix_unitaire, 2) + round(quantite * prix_unitaire * tva_rate / 100, 2))
    INTO v_ttc_d FROM quote.ligne WHERE devis_id = v_devis_id;
  SELECT sum(round(quantite * prix_unitaire, 2) + round(quantite * prix_unitaire * tva_rate / 100, 2))
    INTO v_ttc_f FROM quote.ligne WHERE facture_id = v_facture_id;
  RETURN NEXT is(v_ttc_f, v_ttc_d, 'TTC devis = TTC facture');

  UPDATE project.chantier SET devis_id = NULL WHERE devis_id IS NOT NULL;
  DELETE FROM quote.ligne;
  DELETE FROM quote.facture;
  DELETE FROM quote.devis;
END;
$function$;
COMMENT ON FUNCTION quote_ut.test_devis_facturer() IS 'Test conversion devis accepté -> facture avec copie des lignes';

CREATE OR REPLACE FUNCTION quote_ut.test_devis_lifecycle()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int;
  v_client_id int;
BEGIN
  UPDATE project.chantier SET devis_id = NULL WHERE devis_id IS NOT NULL;
  DELETE FROM quote.ligne;
  DELETE FROM quote.facture;
  DELETE FROM quote.devis;

  SELECT id INTO v_client_id FROM crm.client LIMIT 1;

  -- Créer un brouillon via API
  PERFORM quote.post_devis_save(jsonb_build_object('client_id', v_client_id, 'objet', 'Test lifecycle'));
  SELECT id INTO v_id FROM quote.devis ORDER BY id DESC LIMIT 1;

  RETURN NEXT is((SELECT statut FROM quote.devis WHERE id = v_id), 'brouillon', 'Nouveau devis = brouillon');

  -- brouillon -> envoye
  PERFORM quote.post_devis_envoyer(jsonb_build_object('id', v_id));
  RETURN NEXT is((SELECT statut FROM quote.devis WHERE id = v_id), 'envoye', 'Transition brouillon -> envoye');

  -- envoye -> accepte
  PERFORM quote.post_devis_accepter(jsonb_build_object('id', v_id));
  RETURN NEXT is((SELECT statut FROM quote.devis WHERE id = v_id), 'accepte', 'Transition envoye -> accepte');

  -- Transition invalide : accepte -> envoye
  RETURN NEXT throws_ok(
    format('SELECT quote.post_devis_envoyer(''{"id":%s}''::jsonb)', v_id),
    'Transition invalide: accepte -> envoye'
  );

  -- Test refus: nouveau brouillon -> envoye -> refuse
  PERFORM quote.post_devis_save(jsonb_build_object('client_id', v_client_id, 'objet', 'Test refus'));
  SELECT id INTO v_id FROM quote.devis ORDER BY id DESC LIMIT 1;

  PERFORM quote.post_devis_envoyer(jsonb_build_object('id', v_id));
  PERFORM quote.post_devis_refuser(jsonb_build_object('id', v_id));
  RETURN NEXT is((SELECT statut FROM quote.devis WHERE id = v_id), 'refuse', 'Transition envoye -> refuse');

  UPDATE project.chantier SET devis_id = NULL WHERE devis_id IS NOT NULL;
  DELETE FROM quote.ligne;
  DELETE FROM quote.facture;
  DELETE FROM quote.devis;
END;
$function$;
COMMENT ON FUNCTION quote_ut.test_devis_lifecycle() IS 'Test des transitions de statut devis';

CREATE OR REPLACE FUNCTION quote_ut.test_facture_lifecycle()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int;
  v_client_id int;
BEGIN
  UPDATE project.chantier SET devis_id = NULL WHERE devis_id IS NOT NULL;
  DELETE FROM quote.ligne;
  DELETE FROM quote.facture;
  DELETE FROM quote.devis;

  SELECT id INTO v_client_id FROM crm.client LIMIT 1;

  PERFORM quote.post_facture_save(jsonb_build_object('client_id', v_client_id, 'objet', 'Test lifecycle'));
  SELECT id INTO v_id FROM quote.facture ORDER BY id DESC LIMIT 1;

  RETURN NEXT is((SELECT statut FROM quote.facture WHERE id = v_id), 'brouillon', 'Nouvelle facture = brouillon');

  -- brouillon -> envoyee
  PERFORM quote.post_facture_envoyer(jsonb_build_object('id', v_id));
  RETURN NEXT is((SELECT statut FROM quote.facture WHERE id = v_id), 'envoyee', 'Transition brouillon -> envoyee');

  -- envoyee -> payee
  PERFORM quote.post_facture_payer(jsonb_build_object('id', v_id));
  RETURN NEXT is((SELECT statut FROM quote.facture WHERE id = v_id), 'payee', 'Transition envoyee -> payee');
  RETURN NEXT isnt((SELECT paid_at FROM quote.facture WHERE id = v_id), NULL, 'paid_at renseigné');

  -- Transition invalide
  RETURN NEXT throws_ok(
    format('SELECT quote.post_facture_envoyer(''{"id":%s}''::jsonb)', v_id),
    'Transition invalide: payee -> envoyee'
  );

  -- Suppression non-brouillon impossible
  RETURN NEXT throws_ok(
    format('SELECT quote.post_facture_supprimer(''{"id":%s}''::jsonb)', v_id),
    'Seuls les brouillons peuvent être supprimés'
  );

  UPDATE project.chantier SET devis_id = NULL WHERE devis_id IS NOT NULL;
  DELETE FROM quote.ligne;
  DELETE FROM quote.facture;
  DELETE FROM quote.devis;
END;
$function$;
COMMENT ON FUNCTION quote_ut.test_facture_lifecycle() IS 'Test des transitions de statut facture';

CREATE OR REPLACE FUNCTION quote_ut.test_ligne_parent_check()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_devis_id int;
  v_client_id int;
BEGIN
  UPDATE project.chantier SET devis_id = NULL WHERE devis_id IS NOT NULL;
  DELETE FROM quote.ligne;
  DELETE FROM quote.facture;
  DELETE FROM quote.devis;

  SELECT id INTO v_client_id FROM crm.client LIMIT 1;

  PERFORM quote.post_devis_save(jsonb_build_object('client_id', v_client_id, 'objet', 'Test XOR'));
  SELECT id INTO v_devis_id FROM quote.devis ORDER BY id DESC LIMIT 1;

  -- Ligne sans parent -> erreur XOR
  RETURN NEXT throws_ok(
    'INSERT INTO quote.ligne (description, prix_unitaire) VALUES (''Orphan'', 10)',
    23514,
    'new row for relation "ligne" violates check constraint "ligne_parent_xor"'
  );

  -- Ligne avec les deux parents -> erreur XOR
  RETURN NEXT throws_ok(
    format('INSERT INTO quote.ligne (devis_id, facture_id, description, prix_unitaire) VALUES (%s, 1, ''Both'', 10)', v_devis_id),
    23514
  );

  -- Ajout ligne sur devis non-brouillon -> erreur
  PERFORM quote.post_devis_envoyer(jsonb_build_object('id', v_devis_id));
  RETURN NEXT throws_ok(
    format('SELECT quote.post_ligne_ajouter(''{"devis_id":%s,"description":"Test","prix_unitaire":10}''::jsonb)', v_devis_id),
    'Lignes modifiables uniquement sur un brouillon'
  );

  UPDATE project.chantier SET devis_id = NULL WHERE devis_id IS NOT NULL;
  DELETE FROM quote.ligne;
  DELETE FROM quote.devis;
END;
$function$;
COMMENT ON FUNCTION quote_ut.test_ligne_parent_check() IS 'Test contrainte XOR parent et protection brouillon sur lignes';

CREATE OR REPLACE FUNCTION quote_ut.test_ligne_totals()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int;
  v_client_id int;
  v_ht numeric(12,2);
  v_tva numeric(12,2);
  v_ttc numeric(12,2);
BEGIN
  UPDATE project.chantier SET devis_id = NULL WHERE devis_id IS NOT NULL;
  DELETE FROM quote.ligne;
  DELETE FROM quote.facture;
  DELETE FROM quote.devis;

  SELECT id INTO v_client_id FROM crm.client LIMIT 1;

  PERFORM quote.post_devis_save(jsonb_build_object('client_id', v_client_id, 'objet', 'Test totaux'));
  SELECT id INTO v_id FROM quote.devis ORDER BY id DESC LIMIT 1;

  -- 3h à 45.50 EUR, TVA 10%
  PERFORM quote.post_ligne_ajouter(jsonb_build_object(
    'devis_id', v_id, 'description', 'Main oeuvre',
    'quantite', 3, 'unite', 'h', 'prix_unitaire', 45.50, 'tva_rate', 10
  ));
  -- 2.5 m2 à 35 EUR, TVA 20%
  PERFORM quote.post_ligne_ajouter(jsonb_build_object(
    'devis_id', v_id, 'description', 'Carrelage',
    'quantite', 2.5, 'unite', 'm2', 'prix_unitaire', 35, 'tva_rate', 20
  ));

  -- Calculer via SQL direct (arrondi par ligne) — pas d'appel cross-schema aux _helpers
  SELECT sum(round(quantite * prix_unitaire, 2)) INTO v_ht
    FROM quote.ligne WHERE devis_id = v_id;
  SELECT sum(round(quantite * prix_unitaire * tva_rate / 100, 2)) INTO v_tva
    FROM quote.ligne WHERE devis_id = v_id;
  v_ttc := v_ht + v_tva;

  -- HT: round(3*45.50, 2) + round(2.5*35, 2) = 136.50 + 87.50 = 224.00
  RETURN NEXT is(v_ht, 224.00::numeric(12,2), 'Total HT = 224.00');

  -- TVA: round(3*45.50*10/100, 2) + round(2.5*35*20/100, 2) = 13.65 + 17.50 = 31.15
  RETURN NEXT is(v_tva, 31.15::numeric(12,2), 'Total TVA = 31.15 (arrondi par ligne)');

  -- TTC = HT + TVA
  RETURN NEXT is(v_ttc, 255.15::numeric(12,2), 'Total TTC = 255.15');

  UPDATE project.chantier SET devis_id = NULL WHERE devis_id IS NOT NULL;
  DELETE FROM quote.ligne;
  DELETE FROM quote.devis;
END;
$function$;
COMMENT ON FUNCTION quote_ut.test_ligne_totals() IS 'Test calcul des totaux HT/TVA/TTC avec arrondi par ligne';

CREATE OR REPLACE FUNCTION quote_ut.test_next_numero()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_num1 text;
  v_num2 text;
  v_year text := to_char(now(), 'YYYY');
  v_client_id int;
BEGIN
  -- Cleanup (respect FK order)
  UPDATE project.chantier SET devis_id = NULL WHERE devis_id IS NOT NULL;
  DELETE FROM quote.ligne;
  DELETE FROM quote.facture;
  DELETE FROM quote.devis;

  SELECT id INTO v_client_id FROM crm.client LIMIT 1;

  -- Créer un premier devis via post_devis_save
  PERFORM quote.post_devis_save(jsonb_build_object('client_id', v_client_id, 'objet', 'Test 1'));
  SELECT numero INTO v_num1 FROM quote.devis ORDER BY id DESC LIMIT 1;
  RETURN NEXT is(v_num1, 'DEV-' || v_year || '-001', 'Premier devis = 001');

  -- Deuxième devis
  PERFORM quote.post_devis_save(jsonb_build_object('client_id', v_client_id, 'objet', 'Test 2'));
  SELECT numero INTO v_num2 FROM quote.devis ORDER BY id DESC LIMIT 1;
  RETURN NEXT is(v_num2, 'DEV-' || v_year || '-002', 'Deuxième devis = 002');

  -- Première facture
  PERFORM quote.post_facture_save(jsonb_build_object('client_id', v_client_id, 'objet', 'Facture 1'));
  SELECT numero INTO v_num1 FROM quote.facture ORDER BY id DESC LIMIT 1;
  RETURN NEXT is(v_num1, 'FAC-' || v_year || '-001', 'Première facture = 001');

  -- Test MAX+1 robustesse: supprimer le premier devis, le suivant doit être 003
  DELETE FROM quote.devis WHERE numero = 'DEV-' || v_year || '-001';
  PERFORM quote.post_devis_save(jsonb_build_object('client_id', v_client_id, 'objet', 'Test 3'));
  SELECT numero INTO v_num1 FROM quote.devis ORDER BY id DESC LIMIT 1;
  RETURN NEXT is(v_num1, 'DEV-' || v_year || '-003', 'Après suppression = 003 (MAX+1, pas count)');

  -- Cleanup
  UPDATE project.chantier SET devis_id = NULL WHERE devis_id IS NOT NULL;
  DELETE FROM quote.ligne;
  DELETE FROM quote.facture;
  DELETE FROM quote.devis;
END;
$function$;
COMMENT ON FUNCTION quote_ut.test_next_numero() IS 'Test numérotation séquentielle DEV/FAC via API publique';

CREATE OR REPLACE FUNCTION quote_ut.test_post_devis_dupliquer()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_client_id int;
  v_devis_id int;
  v_new_id int;
  v_count int;
BEGIN
  -- cleanup
  UPDATE project.chantier SET devis_id = NULL WHERE devis_id IS NOT NULL;
  DELETE FROM quote.ligne;
  DELETE FROM quote.facture;
  DELETE FROM quote.devis;

  -- use existing client
  SELECT id INTO v_client_id FROM crm.client LIMIT 1;

  INSERT INTO quote.devis (numero, client_id, objet, statut)
    VALUES ('DEV-2099-001', v_client_id, 'Devis original', 'envoye')
    RETURNING id INTO v_devis_id;
  INSERT INTO quote.ligne (devis_id, description, quantite, prix_unitaire, tva_rate)
    VALUES (v_devis_id, 'Ligne A', 2, 100.00, 20.00),
           (v_devis_id, 'Ligne B', 1, 50.00, 5.50);

  -- duplicate (function uses 'id' key)
  PERFORM quote.post_devis_dupliquer(jsonb_build_object('id', v_devis_id));

  -- new devis created
  SELECT id INTO v_new_id FROM quote.devis WHERE id <> v_devis_id AND client_id = v_client_id;
  RETURN NEXT ok(v_new_id IS NOT NULL, 'duplicate devis created');

  -- statut = brouillon
  RETURN NEXT is(
    (SELECT statut FROM quote.devis WHERE id = v_new_id),
    'brouillon', 'duplicate is brouillon');

  -- lignes copied
  SELECT count(*) INTO v_count FROM quote.ligne WHERE devis_id = v_new_id;
  RETURN NEXT is(v_count, 2, 'lignes copied');

  -- different numero
  RETURN NEXT isnt(
    (SELECT numero FROM quote.devis WHERE id = v_new_id),
    'DEV-2099-001', 'different numero');

  -- error on missing devis
  RETURN NEXT throws_ok(
    'SELECT quote.post_devis_dupliquer(''{"id": 999999}''::jsonb)',
    'P0001', NULL, 'error on missing devis');

  -- cleanup
  UPDATE project.chantier SET devis_id = NULL WHERE devis_id IS NOT NULL;
  DELETE FROM quote.ligne;
  DELETE FROM quote.facture;
  DELETE FROM quote.devis;
END;
$function$;
COMMENT ON FUNCTION quote_ut.test_post_devis_dupliquer() IS 'Test devis duplication feature';

CREATE OR REPLACE FUNCTION quote_ut.test_post_devis_facturer()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN QUERY SELECT * FROM quote_ut.test_devis_facturer();
  -- Branche: devis introuvable
  RETURN NEXT throws_ok(
    'SELECT quote.post_devis_facturer(''{"id":999999}''::jsonb)',
    'Devis introuvable'
  );
END;
$function$;
COMMENT ON FUNCTION quote_ut.test_post_devis_facturer() IS 'Test conversion devis -> facture + branche devis introuvable';

CREATE OR REPLACE FUNCTION quote_ut.test_post_facture_relancer()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_client_id int;
  v_fac_id int;
  v_result text;
BEGIN
  -- cleanup
  UPDATE project.chantier SET devis_id = NULL WHERE devis_id IS NOT NULL;
  DELETE FROM quote.ligne;
  DELETE FROM quote.facture;
  DELETE FROM quote.devis;

  -- use existing client
  SELECT id INTO v_client_id FROM crm.client LIMIT 1;

  -- setup: facture envoyee created 45 days ago
  INSERT INTO quote.facture (numero, client_id, objet, statut, created_at)
    VALUES ('FAC-2099-001', v_client_id, 'Facture test', 'envoyee', now() - interval '45 days')
    RETURNING id INTO v_fac_id;

  -- relance succeeds
  v_result := quote.post_facture_relancer(jsonb_build_object('p_id', v_fac_id));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'relance returns success toast');

  -- statut changed to relance
  RETURN NEXT is(
    (SELECT statut FROM quote.facture WHERE id = v_fac_id),
    'relance', 'statut changed to relance');

  -- notes updated
  RETURN NEXT ok(
    (SELECT notes FROM quote.facture WHERE id = v_fac_id) LIKE '%[Relance%',
    'notes contain relance entry');

  -- error: already relancee (not envoyee anymore)
  RETURN NEXT throws_ok(
    format('SELECT quote.post_facture_relancer(''{"p_id": %s}''::jsonb)', v_fac_id),
    'P0001', NULL, 'error on non-envoyee facture');

  -- error: brouillon facture
  UPDATE quote.facture SET statut = 'brouillon' WHERE id = v_fac_id;
  RETURN NEXT throws_ok(
    format('SELECT quote.post_facture_relancer(''{"p_id": %s}''::jsonb)', v_fac_id),
    'P0001', NULL, 'error on brouillon facture');

  -- error: facture too recent (< 30 days)
  UPDATE quote.facture SET statut = 'envoyee', created_at = now() - interval '10 days' WHERE id = v_fac_id;
  RETURN NEXT throws_ok(
    format('SELECT quote.post_facture_relancer(''{"p_id": %s}''::jsonb)', v_fac_id),
    'P0001', NULL, 'error on recent facture');

  -- error: missing facture
  RETURN NEXT throws_ok(
    'SELECT quote.post_facture_relancer(''{"p_id": 999999}''::jsonb)',
    'P0001', NULL, 'error on missing facture');

  -- cleanup
  DELETE FROM quote.ligne;
  DELETE FROM quote.facture;
  DELETE FROM quote.devis;
END;
$function$;
COMMENT ON FUNCTION quote_ut.test_post_facture_relancer() IS 'Test facture relance (late payment reminder) feature';

CREATE OR REPLACE FUNCTION quote_ut.test_post_ligne_ajouter()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_devis_id int;
  v_facture_id int;
  v_client_id int;
  v_count int;
BEGIN
  UPDATE project.chantier SET devis_id = NULL WHERE devis_id IS NOT NULL;
  DELETE FROM quote.ligne;
  DELETE FROM quote.facture;
  DELETE FROM quote.devis;

  SELECT id INTO v_client_id FROM crm.client LIMIT 1;

  -- Ajout ligne sur devis brouillon
  PERFORM quote.post_devis_save(jsonb_build_object('client_id', v_client_id, 'objet', 'Test ligne'));
  SELECT id INTO v_devis_id FROM quote.devis ORDER BY id DESC LIMIT 1;

  PERFORM quote.post_ligne_ajouter(jsonb_build_object(
    'devis_id', v_devis_id, 'description', 'Prestation', 'quantite', 2, 'unite', 'h', 'prix_unitaire', 50, 'tva_rate', 20
  ));
  SELECT count(*)::int INTO v_count FROM quote.ligne WHERE devis_id = v_devis_id;
  RETURN NEXT is(v_count, 1, 'Ligne ajoutée sur devis');

  -- Ajout ligne sur facture brouillon
  PERFORM quote.post_facture_save(jsonb_build_object('client_id', v_client_id, 'objet', 'Test ligne fac'));
  SELECT id INTO v_facture_id FROM quote.facture ORDER BY id DESC LIMIT 1;

  PERFORM quote.post_ligne_ajouter(jsonb_build_object(
    'facture_id', v_facture_id, 'description', 'Service', 'quantite', 1, 'unite', 'forfait', 'prix_unitaire', 100, 'tva_rate', 20
  ));
  SELECT count(*)::int INTO v_count FROM quote.ligne WHERE facture_id = v_facture_id;
  RETURN NEXT is(v_count, 1, 'Ligne ajoutée sur facture');

  -- Ajout sans parent -> erreur
  RETURN NEXT throws_ok(
    'SELECT quote.post_ligne_ajouter(''{"description":"Orphan","prix_unitaire":10}''::jsonb)',
    'devis_id ou facture_id requis'
  );

  -- Ajout sur devis non-brouillon -> erreur
  PERFORM quote.post_devis_envoyer(jsonb_build_object('id', v_devis_id));
  RETURN NEXT throws_ok(
    format('SELECT quote.post_ligne_ajouter(''{"devis_id":%s,"description":"X","prix_unitaire":10}''::jsonb)', v_devis_id),
    'Lignes modifiables uniquement sur un brouillon'
  );

  -- Ajout sur facture non-brouillon -> erreur
  PERFORM quote.post_facture_envoyer(jsonb_build_object('id', v_facture_id));
  RETURN NEXT throws_ok(
    format('SELECT quote.post_ligne_ajouter(''{"facture_id":%s,"description":"X","prix_unitaire":10}''::jsonb)', v_facture_id),
    'Lignes modifiables uniquement sur un brouillon'
  );

  UPDATE project.chantier SET devis_id = NULL WHERE devis_id IS NOT NULL;
  DELETE FROM quote.ligne;
  DELETE FROM quote.facture;
  DELETE FROM quote.devis;
END;
$function$;
COMMENT ON FUNCTION quote_ut.test_post_ligne_ajouter() IS 'Test ajout de lignes sur devis et facture + branches erreur';

